 1	import { create } from 'zustand'
 2	import { persist } from 'zustand/middleware'
 3	
 4	export interface CartItem {
 5	  productId: string
 6	  name: string
 7	  price: number
 8	  quantity: number
 9	  image?: string
10	}
11	
12	interface CartStore {
13	  items: CartItem[]
14	  addItem: (item: CartItem) => void
15	  removeItem: (productId: string) => void
16	  updateQuantity: (productId: string, quantity: number) => void
17	  clearCart: () => void
18	  getTotal: () => number
19	  getItemCount: () => number
20	}
21	
22	export const useCart = create<CartStore>()(
23	  persist(
24	    (set, get) => ({
25	      items: [],
26	      
27	      addItem: (item) => set((state) => {
28	        const existing = state.items.find(i => i.productId === item.productId)
29	        if (existing) {
30	          return {
31	            items: state.items.map(i =>
32	              i.productId === item.productId
33	                ? { ...i, quantity: i.quantity + item.quantity }
34	                : i
35	            )
36	          }
37	        }
38	        return { items: [...state.items, item] }
39	      }),
40	      
41	      removeItem: (productId) => set((state) => ({
42	        items: state.items.filter(i => i.productId !== productId)
43	      })),
44	      
45	      updateQuantity: (productId, quantity) => set((state) => {
46	        if (quantity <= 0) {
47	          return { items: state.items.filter(i => i.productId !== productId) }
48	        }
49	        return {
50	          items: state.items.map(i =>
51	            i.productId === productId ? { ...i, quantity } : i
52	          )
53	        }
54	      }),
55	      
56	      clearCart: () => set({ items: [] }),
57	      
58	      getTotal: () => get().items.reduce((sum, item) => sum + item.price * item.quantity, 0),
59	      
60	      getItemCount: () => get().items.reduce((sum, item) => sum + item.quantity, 0),
61	    }),
62	    {
63	      name: 'ihhashi-cart',
64	    }
65	  )
66	)

