                <><Loader2 className="w-5 h-5 animate-spin" /> Processing...</>
              ) : (
                <>
                  Place Order
                  <ChevronRight className="w-5 h-5" />
                </>
              )}
            </button>
          </div>
          {!isAuthenticated && (
            <p className="text-xs text-center text-gray-500">
              You'll be asked to sign in before completing your order
            </p>
          )}
        </div>
      </div>
    </div>
  )
}
"}

