} from 'lucide-react'
import { useQuery } from '@tanstack/react-query'
import { ordersAPI } from '../lib/api'
import { useAuth } from '../App'

interface OrderStatus {
  status: string
  label: string
  description: string
  icon: any
  color: string
  bgColor: string
}

const orderStatuses: OrderStatus[] = [
  { 
    status: 'pending', 
    label: 'Order Placed', 
    description: 'We\'ve received your order',
    icon: CheckCircle2,
    color: 'text-yellow-600',
    bgColor: 'bg-yellow-50'
  },
  { 
    status: 'confirmed', 
    label: 'Confirmed', 
    description: 'Restaurant is preparing',
    icon: ChefHat,
    color: 'text-blue-600',
    bgColor: 'bg-blue-50'
  },
  { 
    status: 'preparing', 
    label: 'Preparing', 
    description: 'Your food is being made',
    icon: ChefHat,
    color: 'text-purple-600',
    bgColor: 'bg-purple-50'
  },
  { 
    status: 'ready', 
    label: 'Ready for Pickup', 
    description: 'Waiting for driver',
    icon: Package,
    color: 'text-indigo-600',
    bgColor: 'bg-indigo-50'
  },
  { 
    status: 'picked_up', 
    label: 'Picked Up', 
    description: 'Driver has your order',
    icon: Bike,
    color: 'text-orange-600',
    bgColor: 'bg-orange-50'
  },
  { 
    status: 'in_transit', 
    label: 'On the Way', 
    description: 'Heading to you',
    icon: Bike,
    color: 'text-orange-600',
    bgColor: 'bg-orange-50'
  },
  { 
    status: 'delivered', 
    label: 'Delivered', 
    description: 'Enjoy your meal!',
    icon: Home,
    color: 'text-green-600',
    bgColor: 'bg-green-50'
  },
]

export function OrderTrackingPage() {
  const { id: orderId } = useParams<{ id: string }>()
  const navigate = useNavigate()
  const { isAuthenticated } = useAuth()
  const [copied, setCopied] = useState(false)
  const [showRating, setShowRating] = useState(false)
  const [rating, setRating] = useState(0)

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/auth', { replace: true })
    }
  }, [isAuthenticated, navigate])

  const { data: orderData, isLoading, refetch } = useQuery({
    queryKey: ['order-tracking', orderId],
    queryFn: () => ordersAPI.get(orderId!).then(r => r.data),
    enabled: !!orderId && isAuthenticated,
    refetchInterval: 10_000, // Poll every 10 seconds for live updates
  })

  const order = orderData

  const getCurrentStatusIndex = () => {
    if (!order) return 0
    const index = orderStatuses.findIndex(s => s.status === order.status)
    return index >= 0 ? index : 0
  }

  const currentStatusIndex = getCurrentStatusIndex()
  const isDelivered = order?.status === 'delivered'
  const isActive = !isDelivered && order?.status !== 'cancelled'

  const handleCopyOrderId = () => {
    if (order?.id) {
      navigator.clipboard.writeText(order.id)
      setCopied(true)
      setTimeout(() => setCopied(false), 2000)
    }
  }

  const handleShare = async () => {
    if (navigator.share && order) {
      try {
        await navigator.share({
          title: `iHhashi Order #${order.id?.slice(-8).toUpperCase()}`,
          text: `Track my iHhashi order! Status: ${orderStatuses[currentStatusIndex]?.label}`,
          url: window.location.href,
        })
      } catch {
        // User cancelled share
      }
    }
  }

  const handleSubmitRating = async () => {
    if (rating > 0 && order) {
      try {
        await ordersAPI.rate(order.id, rating)
        setShowRating(false)
        refetch()
      } catch (err) {
        console.error('Failed to submit rating:', err)
      }
    }
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
